#!/bin/bash
# Fix maritime.ts on production server
# Run from /opt/worldpulse

set -e

# Step 1: Write the corrected maritime.ts via base64 decode
echo "=== Writing corrected maritime.ts ==="
base64 -d << 'B64EOF' > apps/api/src/routes/maritime.ts

B64EOF

echo "=== File written, verifying fix ==="
grep -n "whereIn.*status.*verified.*pending" apps/api/src/routes/maritime.ts | head -5

echo "=== Clearing Redis maritime caches ==="
docker exec wp_redis redis-cli -a wp_redis_local DEL maritime:overview maritime:vessels

echo "=== Rebuilding API container ==="
docker compose -f docker-compose.prod.yml up -d --build --no-deps wp_api

echo "=== Done! Wait ~30s for container to become healthy, then test ==="
